const raw = $input.first().json;
const outputText = (raw.output ?? JSON.stringify(raw)).trim();

// Extract first valid JSON object — guards against duplicated memory output
function extractFirstJson(text) {
  let depth = 0, start = -1;
  for (let i = 0; i < text.length; i++) {
    if (text[i] === '{') { if (depth === 0) start = i; depth++; }
    else if (text[i] === '}') { depth--; if (depth === 0 && start !== -1) return text.slice(start, i + 1); }
  }
  return text;
}

let parsed;
try {
  const stripped = outputText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
  const clean = extractFirstJson(stripped);
  parsed = JSON.parse(clean);
  if (Array.isArray(parsed)) parsed = parsed[0] ?? parsed;
} catch {
  return [{ json: { output: outputText, parse_error: true } }];
}

// Normalize agent key aliases → canonical playbook key_term_names
const KEY_ALIASES = {
  monthly_payment: 'annual_payment',
  annual_rent: 'annual_payment',
  renewal_option: 'renewal_options',
  right_of_use_asset: 'rou_asset_scope',
  rou_asset: 'rou_asset_scope',
  lease_liability: null,  // not a playbook field — discard
  lease_term: null,       // not a scored field — discard
};

// key_terms[] → fields{} shape the frontend expects
const RISK_WEIGHTS = {
  commencement_date: 10, expiry_date: 10, annual_payment: 10, discount_rate: 10,
  renewal_options: 8, termination_rights: 8, escalation_rate: 7,
  rou_asset_scope: 6, security_deposit: 5, governing_law: 3,
};

const fields = {};
for (const item of (parsed.key_terms ?? [])) {
  let key = item.key ?? item.label.toLowerCase().replace(/[^a-z0-9]+/g, '_');
  if (key in KEY_ALIASES) {
    if (KEY_ALIASES[key] === null) continue; // discard non-playbook fields
    key = KEY_ALIASES[key];
  }
  if (fields[key]) continue; // first occurrence wins
  const missing = !item.value || item.value === 'Not specified';
  fields[key] = {
    value: missing ? null : item.value,
    confidence: missing ? 0 : (item.confidence ?? 0.85),
    source_clause: item.source_clause ?? null,
  };
}

// Ensure all playbook fields are present (fill missing ones with null)
for (const key of Object.keys(RISK_WEIGHTS)) {
  if (!fields[key]) fields[key] = { value: null, confidence: 0, source_clause: null };
}

const isMissing = (f) => !f || f.value === null || f.value === undefined;
const terms_found   = Object.keys(fields).filter(k => !isMissing(fields[k]));
const terms_missing = Object.keys(fields).filter(k =>  isMissing(fields[k]));

const totalWeight   = Object.values(RISK_WEIGHTS).reduce((s, w) => s + w, 0);
const missingWeight = terms_missing.reduce((s, k) => s + (RISK_WEIGHTS[k] ?? 0), 0);
const risk_score    = Math.round(100 * (1 - missingWeight / totalWeight));

const risk_flags = terms_missing.map(key => {
  const w        = RISK_WEIGHTS[key] ?? 0;
  const severity = w >= 8 ? 'high' : w >= 5 ? 'medium' : 'low';
  return {
    id: `missing_${key}`,
    severity,
    title: `${key.replace(/_/g, ' ')} not found`,
    description: severity === 'high'
      ? 'Required for IFRS 16 compliance — resolve before exporting the report.'
      : 'Verify manually and update if applicable.',
    field: key,
  };
});

return [{
  json: {
    contract_type: parsed.contract_type ?? 'LEASE',
    terms_found,
    terms_missing,
    risk_score,
    analyzed_at: new Date().toISOString(),
    key_terms: parsed.key_terms ?? [],
    fields,
    risk_flags,
  }
}];
